<?php
namespace App\Domain\Accounting\Actions;
use App\Models\AccountingPeriod;use App\Models\AccountingPostingRule;use App\Models\LedgerAccount;use Carbon\CarbonImmutable;
class ProvisionAccounting{public function execute(int $financialYearStartMonth=1):void{$accounts=[['1000','Cash and Bank','asset','debit'],['1100','Loan Receivables','asset','debit'],['1200','Payout Clearing','asset','debit'],['2000','Member Savings','liability','credit'],['2100','Member Contributions','liability','credit'],['2200','Unallocated Collections','liability','credit'],['3000','Members Equity','equity','credit'],['4000','Interest Income','income','credit'],['4100','Fee Income','income','credit'],['4200','Penalty Income','income','credit'],['4300','Recovery Cost Reimbursement','income','credit'],['5000','Operating Expenses','expense','debit']];$ids=[];foreach($accounts as [$code,$name,$type,$normal])$ids[$code]=LedgerAccount::query()->firstOrCreate(['code'=>$code],['name'=>$name,'type'=>$type,'normal_balance'=>$normal,'is_control_account'=>in_array($code,['1100','2000','2100'],true),'allows_direct_posting'=>true,'is_system'=>true,'is_active'=>true])->id;$rules=['collection.contribution'=>['1000','2100'],'collection.savings'=>['1000','2000'],'collection.unallocated'=>['1000','2200'],'loan.principal_recognized'=>['1100','1200'],'loan.charge_added'=>['1100','4100'],'loan.disbursement_paid'=>['1200','1000'],'loan.disbursement_charge'=>['1200','4100'],'repayment.principal'=>['1000','1100'],'repayment.interest'=>['1000','4000'],'repayment.charges'=>['1000','1100'],'repayment.penalties'=>['1000','1100'],'repayment.recovery_expenses'=>['1000','1100'],'penalty.assessed'=>['1100','4200'],'recovery.expense_assessed'=>['1100','4300'],'savings.withdrawal_paid'=>['2000','1000'],'savings.withdrawal_fee'=>['2000','4100']];foreach($rules as $event=>[$debit,$credit])AccountingPostingRule::query()->firstOrCreate(['event_type'=>$event],['debit_account_id'=>$ids[$debit],'credit_account_id'=>$ids[$credit],'description_template'=>str($event)->replace('.',' ')->headline().' {reference}','is_active'=>true]);$today=CarbonImmutable::today();$start=$today->month>=$financialYearStartMonth?$today->setMonth($financialYearStartMonth)->startOfMonth():$today->subYear()->setMonth($financialYearStartMonth)->startOfMonth();$end=$start->addYear()->subDay();AccountingPeriod::query()->firstOrCreate(['start_date'=>$start->toDateString(),'end_date'=>$end->toDateString()],['name'=>'FY '.$start->year.'/'.$end->year,'status'=>'open']);}}
